mapper.select:
SELECT m.消息编号, m.消息类型, m.消息分类, m.消息标题, m.消息内容, m.消息优先级, m.接收人编码, m.发送人编码, m.关联业务类型, m.关联业务ID, m.消息状态, m.创建时间, m.已读时间, m.删除时间, m.备注, receiver.员工姓名 AS 接收人姓名, sender.员工姓名 AS 发送人姓名 FROM MESSAGE m LEFT JOIN EMPLOYEE receiver ON m.接收人编码 = receiver.员工编码 LEFT JOIN EMPLOYEE sender ON m.发送人编码 = sender.员工编码 WHERE m.接收人编码 = #{receiverId} AND m.消息状态 != '已删除'
AND m.消息类型 = #{messageType}
AND m.消息状态 = #{messageStatus}
AND m.消息优先级 = #{messagePriority}
AND (m.消息标题 LIKE CONCAT('%', #{keyword}, '%') OR m.消息内容 LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY CASE m.消息优先级 WHEN '紧急' THEN 1 WHEN '高' THEN 2 WHEN '中' THEN 3 WHEN '低' THEN 4 ELSE 5 END, m.创建时间 DESC

